import{_ as t,c as l,o as h,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.55：超额提示更友好、事件内存泄漏修复","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.55.md","filePath":"changelog/v1.1.55.md","lastUpdated":1772014034000}'),n={name:"changelog/v1.1.55.md"};function i(o,e,d,s,c,p){return h(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-1-55-超额提示更友好、事件内存泄漏修复" tabindex="-1">v1.1.55：超额提示更友好、事件内存泄漏修复 <a class="header-anchor" href="#v1-1-55-超额提示更友好、事件内存泄漏修复" aria-label="Permalink to “v1.1.55：超额提示更友好、事件内存泄漏修复”">​</a></h1><p><strong>发布日期</strong>：2026年02月11日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新重点是「稳定和可预期」：免费额度超限时给出更清晰提示，修复事件抓取内存泄漏，并在桌面端禁用终端透明效果来减少显示问题。</p><hr><h2 id="新功能-免费额度超限提示更清晰" tabindex="-1">新功能：免费额度超限提示更清晰 <a class="header-anchor" href="#新功能-免费额度超限提示更清晰" aria-label="Permalink to “新功能：免费额度超限提示更清晰”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>当免费使用额度超限时，OpenCode 会显示更明确、更可操作的提示信息。</p><h3 id="这对你有什么用" tabindex="-1">这对你有什么用？ <a class="header-anchor" href="#这对你有什么用" aria-label="Permalink to “这对你有什么用？”">​</a></h3><p>你不会再卡在「为什么突然不能继续」的状态里，能更快判断是额度问题还是配置问题。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>👉 <strong>完整教程</strong>：<a href="/1-start/04a-free-models.html">免费模型（OpenCode Zen）</a></p><p>👉 <strong>官方文档</strong>：<a href="https://opencode.ai/docs/zen" target="_blank" rel="noreferrer">Zen</a></p><p><strong>快速体验</strong>：</p><ol><li>使用免费模型持续对话到接近额度上限。</li><li>观察提示文案是否给出明确原因。</li><li>按提示切换模型或等待额度刷新。</li></ol><hr><h2 id="问题修复-事件抓取内存泄漏" tabindex="-1">问题修复：事件抓取内存泄漏 <a class="header-anchor" href="#问题修复-事件抓取内存泄漏" aria-label="Permalink to “问题修复：事件抓取内存泄漏”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>事件抓取路径存在内存泄漏风险，长时间运行后可能出现卡顿或占用升高。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>v1.1.55 已修复相关泄漏点，长会话稳定性更好。</p><hr><h2 id="改进-桌面端禁用终端透明" tabindex="-1">改进：桌面端禁用终端透明 <a class="header-anchor" href="#改进-桌面端禁用终端透明" aria-label="Permalink to “改进：桌面端禁用终端透明”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>桌面端默认关闭终端透明效果。</p><h3 id="这对你有什么用-1" tabindex="-1">这对你有什么用？ <a class="header-anchor" href="#这对你有什么用-1" aria-label="Permalink to “这对你有什么用？”">​</a></h3><p>在不同系统主题和显卡驱动下，终端显示更一致，减少对比度不清和渲染异常。</p><p>👉 <strong>完整教程</strong>：<a href="/5-advanced/22-debugging.html">调试与诊断</a></p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>你在用免费模型</td><td>✅ 建议升级</td></tr><tr><td>你有长时间运行会话</td><td>✅ 建议升级</td></tr><tr><td>你是桌面端用户</td><td>✅ 建议升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',33),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Increase test timeout to 30s to prevent failures during package installation</li><li>Memory leak fixed in platform fetch for events</li><li>Show helpful message when free usage limit is exceeded</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Disable terminal transparency</li></ul><p>官方 Release Notes：</p><ul><li><a href="https://github.com/anomalyco/opencode/releases/tag/v1.1.55" target="_blank" rel="noreferrer">https://github.com/anomalyco/opencode/releases/tag/v1.1.55</a></li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const f=t(n,[["render",i]]);export{m as __pageData,f as default};
